mapper.select:
SELECT (SELECT PRDT_CODE FROM CMN_INTM_MDL@DL_MSP WHERE PRDT_ID = T1.RPRS_PRDT_ID) AS REQ_MODEL_NAME , PRDT_COLR_CD AS REQ_MODEL_COLOR , PRDT_NM , PRDT_ID FROM CMN_INTM_MDL@DL_MSP T1 WHERE 1=1
AND RPRS_PRDT_ID = #{rprsPrdtId}
AND PRDT_ID = #{modelId} AND ROWNUM =1

SELECT C.PRDT_ID AS RPRS_PRDT_ID , PRDT_NM , PRDT_SCTN_CD , B.SPRT_TP , PLCY_SCTN_CD , A.ORGN_ID AS CNTPNT_SHOP_ID , B.SALE_PLCY_CD AS MODEL_SALE_POLICY_CODE , E.OPER_TYPE , D.PRDT_CODE AS REQ_MODEL_NAME , B.INST_RATE , ( SELECT KT_ORG_ID FROM ORG_ORGN_INFO_MST@DL_MSP WHERE 1=1 AND ORGN_ID = #{cntpntShopId} AND ROWNUM = 1 ) AS AGENT_CODE , B.SELF_OPEN_YN FROM MSP_SALE_ORGN_MST@DL_MSP A , MSP_SALE_PLCY_MST@DL_MSP B , MSP_SALE_PRDT_MST@DL_MSP C , CMN_INTM_MDL@DL_MSP D , MSP_SALE_OPER_MST@DL_MSP E , CMN_GRP_CD_MST@DL_MSP F , CMN_HNDST_AMT@DL_MSP G WHERE TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN B.SALE_STRT_DTTM AND B.SALE_END_DTTM AND B.CNFM_YN = 'Y' AND A.SALE_PLCY_CD = B.SALE_PLCY_CD AND B.SALE_PLCY_CD = C.SALE_PLCY_CD AND C.PRDT_ID = D.PRDT_ID AND B.SALE_PLCY_CD = E.SALE_PLCY_CD AND A.ORGN_ID = #{cntpntShopId} AND B.SALE_PLCY_CD = #{modelSalePolicyCode} AND D.RPRS_YN = 'Y' AND D.PRDT_DT = '99991231' AND PRDT_IND_CD = F.CD_VAL AND E.OPER_TYPE = #{operType} AND D.PRDT_CODE = #{reqModelName}
AND B.SPRT_TP = #{sprtTp}
and F.GRP_ID = 'CMN0045' AND PRDT_IND_CD = F.CD_VAL AND C.PRDT_ID = G.RPRS_PRDT_ID AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN G.UNIT_PRIC_APPL_DTTM AND G.UNIT_PRIC_EXPR_DTTM


SELECT  AGRM_TRM AS ENGG_MNTH_CNT
    FROM    MSP_SALE_AGRM_MST@DL_MSP
    WHERE   SALE_PLCY_CD = #{modelSalePolicyCode}

SELECT CONTRACT_NUM, SOC_CODE, SELF_CSTMR_CI FROM ( SELECT T1.CONTRACT_NUM, T4.FST_RATE_CD AS SOC_CODE, T2.SELF_CSTMR_CI FROM ( SELECT REQUEST_KEY, CONTRACT_NUM, ON_OFF_TYPE, SYS_RDATE FROM MCP_REQUEST WHERE ON_OFF_TYPE IN ('5','7','9','0','3') AND OPER_TYPE = 'NAC3'
AND USIM_KINDS_CD = '09' -- eSIM 신청서
AND NVL(USIM_KINDS_CD,'00') <> '09' -- eSIM 아닌것...
) T1 INNER JOIN (SELECT REQUEST_KEY, SELF_CSTMR_CI FROM MCP_REQUEST_CSTMR WHERE SELF_CSTMR_CI = #{selfCstmrCi}
AND CSTMR_NAME = #{cstmrName}
) T2 ON T1.REQUEST_KEY = t2.REQUEST_KEY INNER JOIN MSP_JUO_SUB_INFO@DL_MSP T3 ON T1.CONTRACT_NUM = t3.CONTRACT_NUM INNER JOIN MSP_REQUEST_DTL@DL_MSP T4 ON T3.CONTRACT_NUM = t4.CONTRACT_NUM WHERE 1=1 AND T3.LST_COM_ACTV_DATE > TO_CHAR(SYSDATE-30, 'YYYYMMDD') AND T3.SUB_STATUS <> 'C' ORDER BY T1.SYS_RDATE DESC ) WHERE ROWNUM = 1

SELECT COUNT(*) FROM MSP_REUSE_IP_MST@DL_MSP
AND RIP_STATUS = 'L'
AND RIP = #{stolenIp}

SELECT COUNT(*)
  FROM MSP_JUO_SUB_INFO@DL_MSP A
       , MCP_COMMEND_ID_MNG B
 WHERE A.CONTRACT_NUM = B.CONTRACT_NUM
   AND A.SUB_LINK_NAME = #{name}
   AND A.SUBSCRIBER_NO = #{phone}
   AND B.COMMEND_ID = #{commendId}

mapper.insert:

    SELECT ('AD' || TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_AD.NEXTVAL@DL_MSP, '000000'))) AS APD_SEQ  FROM DUAL

/* AppformMapper.insertDisPrmtApd*/
INSERT INTO MSP_DIS_APD@DL_MSP (
APD_SEQ
,REGST_DT
,PROC_YN
,RES_NO

    ,REQUEST_KEY


    ,CONTRACT_NUM


    ,PRMT_ID

,CHNL_CD
,EVNT_CD
,ENGG_MNTH_CNT
,OPEN_AGNT_CD
,PRMT_AGNT_CD
,RATE_CD
,ON_OFF_TYPE
,OPER_TYPE
,REQ_BUY_TYPE
,REGST_ID
,REGST_DTTM
) VALUES(
#{apdSeq}
,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
,'N'
,#{resNo}

    ,#{requestKey}


    ,#{contractNum}


    ,#{prmtId}

,'01'
,#{evntCd}
,'00'
,#{cntpntShopId}
,#{cntpntShopId}
,#{socCode}
,#{onOffType}
,#{operType}
,#{reqBuyType}


        ,#{cretId}


        ,'MCP'


,SYSDATE
)

mapper.select:
/* AppformMapper.getDisPrmtId*/
SELECT  DISTINCT PRMT_ID
FROM VW_DIS_PRMT_DTL@DL_MSP A
WHERE 1=1
AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN A.STRT_DTTM AND A.END_DTTM
AND USG_YN = 'Y'
AND ORGN_ID = #{cntpntShopId}
AND SLS_TP = #{slsTp}


        AND INTM_YN = 'N'


        AND INTM_YN = 'Y'
        AND MODEL_ID = (SELECT RPRS_PRDT_ID FROM CMN_INTM_MDL@DL_MSP A WHERE PRDT_ID = #{modelId})


/*AND CHNL_TP = 'CS10'*/
AND ENGG_SRL LIKE  '%' || #{enggMnthCnt} || '%'
AND RATE_CD = #{socCode}
AND EVNT_CD = 'NAC'

SELECT DISTINCT B.PRDT_SCTN_CD , B.SELF_OPEN_YN , E.OPER_TYPE , B.SALE_PLCY_CD , C.PRDT_ID , I.AGRM_TRM , B.REGST_DTTM , D.PRDT_NM FROM MSP_SALE_ORGN_MST@DL_MSP A , MSP_SALE_PLCY_MST@DL_MSP B , MSP_SALE_PRDT_MST@DL_MSP C , CMN_INTM_MDL@DL_MSP D , MSP_SALE_OPER_MST@DL_MSP E , CMN_GRP_CD_MST@DL_MSP F , CMN_HNDST_AMT@DL_MSP G , MSP_SALE_RATE_MST@DL_MSP H , MSP_SALE_AGRM_MST@DL_MSP I WHERE TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN B.SALE_STRT_DTTM AND B.SALE_END_DTTM AND B.CNFM_YN = 'Y' AND A.SALE_PLCY_CD = B.SALE_PLCY_CD AND B.SALE_PLCY_CD = C.SALE_PLCY_CD AND C.PRDT_ID = D.PRDT_ID AND B.SALE_PLCY_CD = E.SALE_PLCY_CD AND A.SALE_PLCY_CD = H.SALE_PLCY_CD AND A.SALE_PLCY_CD = I.SALE_PLCY_CD AND A.ORGN_ID = #{cntpntShopId} AND D.RPRS_YN = 'Y' AND D.PRDT_DT = '99991231' AND PRDT_IND_CD = F.CD_VAL and F.GRP_ID = 'CMN0045' AND PRDT_IND_CD = F.CD_VAL AND C.PRDT_ID = G.RPRS_PRDT_ID
AND H.RATE_CD = #{socCode}
AND B.PRDT_SCTN_CD = #{plcySctnCd}
AND B.SALE_PLCY_CD = #{modelSalePolicyCode}
AND TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') BETWEEN G.UNIT_PRIC_APPL_DTTM AND G.UNIT_PRIC_EXPR_DTTM ORDER BY B.REGST_DTTM DESC
